<template><main><header><p>GridVerse</p><h1>Reliability & security analysis</h1></header><Stepper :steps="steps" :active="active"/><section class="panel"><label>Network ID<input v-model="networkId"/></label><label>Contingency / monitored branch IDs<textarea v-model="contingencyText" placeholder="one branch ID per line"/></label><label>PST IDs<textarea v-model="pstText" placeholder="one transformer ID per line"/></label><template v-if="active===4"><label>RAO timestamp<input v-model="timestamp" placeholder="20250505T2330"/></label><label>PST profile ZIP<input type="file" accept=".zip" @change="pickProfile"/></label></template><GvButton :disabled="busy||!networkId||(active===4&&!profileFile)" @click="next">{{busy?'Running…':actionLabel}}</GvButton><p v-if="message">{{message}}</p><p v-if="error" class="error">{{error}}</p></section><section v-if="Object.keys(results).length" class="results"><h2>Run timeline</h2><article v-for="(value,key) in results" :key="key"><h3>{{key}}</h3><pre>{{JSON.stringify(value,null,2)}}</pre></article></section></main></template>
<script setup lang="ts">import{computed,ref}from'vue';import{GvButton,Stepper}from'@gridverse/gui.common/src';import*as api from'./services/rsaApi';const steps=['CGM ready','Load flow','Security','Sensitivity','RAO','Apply actions','Rerun LF/SA','Visualize'];const active=ref(0),networkId=ref(''),workflowId=ref(''),updatedNetwork=ref(''),contingencyText=ref(''),pstText=ref(''),timestamp=ref(''),profileFile=ref<File>(),busy=ref(false),error=ref(''),message=ref('');const results=ref<Record<string,any>>({});const ids=(v:string)=>v.split(/\r?\n/).map(x=>x.trim()).filter(Boolean);const contingencies=()=>ids(contingencyText.value).map(id=>({id:`OUT_${id}`,name:`Outage ${id}`,elementIds:[id]}));const actionLabel=computed(()=>['Start workflow','Run load flow','Run security analysis','Run sensitivity analysis','Run RAO','Apply proposed actions','Rerun LF/SA','Build comparison'][active.value]);function pickProfile(e:Event){profileFile.value=(e.target as HTMLInputElement).files?.[0]}async function next(){busy.value=true;error.value='';try{if(active.value===0){const r=await api.createWorkflow(networkId.value);workflowId.value=r.id;results.value.workflow=r}else if(active.value===1)results.value.loadFlow=await api.runLoadFlow(networkId.value);else if(active.value===2)results.value.security=await api.runSecurity(networkId.value,contingencies());else if(active.value===3)results.value.sensitivity=await api.runSensitivity(networkId.value,ids(contingencyText.value),ids(pstText.value));else if(active.value===4){if(!profileFile.value)throw new Error('Select the PST profile ZIP');results.value.rao=await api.runRaoProfile(networkId.value,timestamp.value,profileFile.value,{branchCurrentsA:results.value.loadFlow?.branchCurrentsA??{},currentSensitivities:results.value.sensitivity?.factors??{}})}else if(active.value===5){const r=await api.applyActions(workflowId.value,results.value.rao?.proposedActions??[]);updatedNetwork.value=r.updatedNetworkId;results.value.actions=r}else if(active.value===6)results.value.rerun=await api.rerun(updatedNetwork.value||networkId.value,contingencies());else{const before=results.value.loadFlow?.branchCurrentsA??{};const after=results.value.rerun?.loadFlow?.branchCurrentsA??{};results.value.visualization=await api.compare(workflowId.value,before,after)}active.value=Math.min(active.value+1,7)}catch(e){error.value=String(e)}finally{busy.value=false}}</script>
<style scoped>main{max-width:1200px;margin:auto;padding:2rem}header p{color:#087e8b;font-weight:800}.panel{background:#fff;padding:1.5rem;border-radius:12px;display:grid;gap:1rem;box-shadow:0 8px 28px #17324d18}label{display:grid;gap:.35rem;font-weight:700}input,textarea{padding:.7rem;border:1px solid #afc2ce;border-radius:6px}textarea{min-height:5rem}.error{color:#b42318}.results{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:1rem;margin-top:1rem}.results h2{grid-column:1/-1}.results article{background:white;padding:1rem;border-radius:10px;overflow:auto}pre{font-size:.72rem}</style>
